import React from "react"
import { Button, Input } from "antd"
import { Row } from "../../components/lib"
import { useSetUrlSearchParam } from "../../utils/url"
import { useTasksSearchParams } from "./util"
import { UserSelect } from "../../components/user-select"
import { TaskTypeSelect } from "../../components/task-type-select"

export const SearchPanel = () => {
    const searcnParams = useTasksSearchParams()
    const setSearchParams = useSetUrlSearchParam()
    const reset = () => {
        setSearchParams({
            typeId: undefined,
            processorId: undefined,
            tagId: undefined,
            name: undefined
        })
    }

    return <Row marginBottom={4} gap={true}>
        <Input style={{width: '20rem'}} placeholder={'任务名'} value={searcnParams.name} 
            onChange={evt =>setSearchParams({name: evt.target.value})}/>
        <UserSelect defaultOptionName={'经办人'} value={searcnParams.processorId}
            onChange={value => setSearchParams({processId: value})}/>
        <TaskTypeSelect defaultOptionName={'类型'} value={searcnParams.typeId} 
            onChange={value => setSearchParams({typeId: value})}/>
        <Button onClick={reset}>清除筛选器</Button>
    </Row>
}